-- INA Basics — Immigrant vs Nonimmigrant
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_104', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1101 (INA § 101 — Definitions)', 'INA § 101 / 8 USC § 1101', 'Immigration and Nationality Act — Immigrant vs Nonimmigrant Classifications', 'Foundation of US immigration law. Defines immigrant (any alien except those in nonimmigrant categories) and nonimmigrant (temporary visitors in enumerated visa categories). INA § 101(a)(15) enumerates all nonimmigrant visa categories (A through V). INA § 201-203 establishes immigrant visa preference categories: family-sponsored (F1-F4), employment-based (EB1-EB5), and diversity visas. Dual intent doctrine applies to H-1B and L-1 but not most other nonimmigrant categories.', '["Immigrant: any alien not classified as nonimmigrant under § 101(a)(15)","Nonimmigrant categories: A (diplomats), B (visitors), F (students), H (workers), J (exchange), K (fiancé), L (intracompany), M (vocational), O (extraordinary), P (athletes/artists), Q (cultural exchange), R (religious), S (informant), T (trafficking), U (crime victim), V (long-wait spouses)","Family-sponsored preferences: F1 (unmarried adult children), F2 (spouses/minor children of LPRs), F3 (married adult children), F4 (siblings)","Employment-based preferences: EB-1 (priority/extraordinary), EB-2 (advanced degree), EB-3 (skilled/professional), EB-4 (special immigrant), EB-5 (investor)","Diversity Visa Lottery: 55,000 visas annually from underrepresented countries","Immediate relatives: spouses, minor children, parents of US citizens — no numerical limit","Lawful Permanent Resident (LPR/green card) is immigrant status","Visa Waiver Program (VWP) countries enter without visa for 90 days"]', '[{"section":"101(a)(15)","description":"Nonimmigrant visa categories A through V"},{"section":"101(a)(20)","description":"Definition of lawful permanent resident"},{"section":"201","description":"Worldwide level of immigration — numerical limits"},{"section":"202","description":"Per-country numerical limitation"},{"section":"203","description":"Allocation of immigrant visas — preference categories"},{"section":"101(a)(42)","description":"Definition of refugee"},{"section":"101(a)(43)","description":"Aggravated felony definition — deportation consequences"}]', '["visa_application","I-130_petition","I-485_adjustment","I-140_petition","DS-260","I-94_arrival_record","green_card","naturalization_application"]', '["california-immigration-compliance-audit"]', 'USCIS / DOS / ICE / CBP', 0, 1, datetime('now'), datetime('now'));

-- Asylum
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_105', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1158 (INA § 208 — Asylum)', 'INA § 208 / 8 USC § 1158', 'Asylum — Protection from Persecution', 'Asylum available to any person physically present in the US who demonstrates past persecution or well-founded fear of future persecution on account of race, religion, nationality, membership in a particular social group, or political opinion. Must file within 1 year of arrival (with limited exceptions for changed or extraordinary circumstances). Affirmative asylum filed with USCIS Asylum Office; defensive asylum before Immigration Judge. Grants work authorization and path to LPR status after 1 year. Bars: firm resettlement, persecutor bar, particularly serious crime, safe third country.', '["Must demonstrate persecution or well-founded fear of persecution","Five protected grounds: race, religion, nationality, particular social group, political opinion","1-year filing deadline from date of last arrival (exceptions: changed circumstances, extraordinary circumstances)","Nexus requirement: persecution must be on account of protected ground","Persecution by government or group government cannot or will not control","Affirmative asylum: filed with USCIS Asylum Office (Form I-589)","Defensive asylum: raised as defense in removal proceedings before IJ","Work authorization: EAD available 180 days after filing (subject to regulatory changes)","Bars: firm resettlement in third country, persecutor bar, particularly serious crime (aggravated felony), terrorist activity","Derivative asylum for spouse and unmarried children under 21","Path to LPR after 1 year in asylum status"]', '[{"section":"208(a)","description":"Authority to apply for asylum — physical presence requirement"},{"section":"208(a)(2)(B)","description":"1-year filing deadline and exceptions"},{"section":"208(a)(2)(C)","description":"Safe third country bar"},{"section":"208(b)(1)(A)","description":"Standard: well-founded fear of persecution"},{"section":"208(b)(1)(B)","description":"Burden of proof — credible testimony may suffice"},{"section":"208(b)(2)","description":"Bars to asylum — persecutor, particularly serious crime, firm resettlement"},{"section":"208(c)(1)","description":"Asylum status and derivative beneficiaries"},{"section":"208(d)","description":"Asylum procedure and employment authorization"}]', '["I-589_asylum_application","asylum_declaration","country_conditions_evidence","expert_declaration","asylum_interview_notice","immigration_court_notice","EAD_application","I-485_asylee_adjustment"]', '["california-immigration-compliance-audit"]', 'USCIS Asylum Office / EOIR Immigration Courts / BIA', 0, 1, datetime('now'), datetime('now'));

-- Withholding of Removal
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_106', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1231(b)(3) (INA § 241(b)(3) — Withholding of Removal)', 'INA § 241(b)(3) / 8 USC § 1231(b)(3)', 'Withholding of Removal — Mandatory Protection from Return', 'Mandatory form of protection: government may not remove an alien to a country where the alien''s life or freedom would be threatened on account of race, religion, nationality, particular social group, or political opinion. Higher burden than asylum (clear probability — more likely than not), but no 1-year filing deadline and no discretionary bars. Does not confer lawful status or path to LPR. Country-specific: alien may be removed to a different country. No derivative benefits for family members.', '["Clear probability standard: more likely than not life or freedom threatened","Same five protected grounds as asylum","No 1-year filing deadline — can be raised at any time in removal proceedings","Mandatory: no discretion to deny if standard met","No bars for firm resettlement or safe third country","Bars: persecutor bar, particularly serious crime (aggregated felony with sentence of 5+ years)","Does not confer lawful immigration status","Country-specific protection only — may be removed elsewhere","No derivative benefits for spouse or children","No path to LPR or citizenship","Filed on same I-589 form as asylum application"]', '[{"section":"241(b)(3)(A)","description":"Prohibition on removal to country of threatened persecution"},{"section":"241(b)(3)(B)","description":"Exceptions — persecutor, particularly serious crime, security danger, serious nonpolitical crime"},{"section":"241(b)(3)(C)","description":"Particularly serious crime — aggravated felony threshold"},{"section":"208.16(b)","description":"8 CFR procedure for withholding claims"}]', '["I-589_withholding_application","immigration_court_brief","country_conditions_evidence","BIA_appeal","withholding_order"]', '["california-immigration-compliance-audit"]', 'EOIR Immigration Courts / BIA / Federal Courts', 0, 1, datetime('now'), datetime('now'));

-- Convention Against Torture
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_107', 'REGULIS', 'FEDERAL_REGULATION', 'US', '8 CFR § 208.16(c) / 8 CFR § 208.17-208.18 (Convention Against Torture Implementation)', 'CAT / 8 CFR § 208.16(c)', 'Convention Against Torture — Protection from Torture upon Return', 'Implements US obligations under Article 3 of the UN Convention Against Torture. Prohibits removal to a country where more likely than not the applicant would be tortured by or with acquiescence of government officials. Two forms: withholding of removal under CAT (can be terminated if conditions change) and deferral of removal under CAT (for those subject to mandatory denial). No bars based on criminal history — available even to aggravated felons. No nexus to protected ground required — purely based on likelihood of torture.', '["Must show more likely than not would be tortured if removed","Torture: severe pain or suffering, intentionally inflicted, by/with acquiescence of public official","Acquiescence: government awareness and breach of duty to intervene","No nexus to protected ground required — differs from asylum","No criminal bars — available even to aggravated felons and persecutors","Withholding under CAT: cannot be removed to designated country, may be terminated if conditions change","Deferral of removal under CAT: for those ineligible for withholding (persecutors, serious criminals), subject to termination","Country-specific: may be removed to different country","No lawful immigration status conferred","All relevant evidence considered: country conditions, past torture, pattern of torture"]', '[{"section":"208.16(c)(1)","description":"Burden of proof — more likely than not would be tortured"},{"section":"208.16(c)(2)","description":"Torture definition — severe pain/suffering by government actor"},{"section":"208.16(c)(3)","description":"Evidence to consider — all relevant, country conditions, past torture"},{"section":"208.17","description":"Deferral of removal under CAT — for mandatory denial cases"},{"section":"208.18(a)","description":"Definition of torture — intentional, severe, government acquiescence"},{"section":"208.18(a)(7)","description":"Acquiescence — awareness plus breach of duty to intervene"}]', '["I-589_CAT_application","country_conditions_report","medical_evidence_of_torture","expert_testimony","immigration_court_brief","State_Department_report","NGO_human_rights_report"]', '["california-immigration-compliance-audit"]', 'EOIR Immigration Courts / BIA / Federal Courts', 0, 1, datetime('now'), datetime('now'));

-- U-Visa
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_108', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1101(a)(15)(U) (INA § 101(a)(15)(U) — U Nonimmigrant Status)', 'INA § 101(a)(15)(U) / U-Visa', 'U-Visa — Immigration Relief for Crime Victims', 'Provides temporary immigration status to victims of qualifying crimes who have suffered substantial physical or mental abuse and are helpful to law enforcement in investigation or prosecution. 10,000 U-visas available annually (cap consistently reached). Requires law enforcement certification (I-918 Supplement B) confirming helpfulness. Grants 4-year nonimmigrant status with work authorization. Path to LPR after 3 years in U status. Derivative visas for qualifying family members.', '["Victim of qualifying crime: domestic violence, sexual assault, trafficking, kidnapping, abduction, torture, incest, and 20+ other enumerated crimes","Substantial physical or mental abuse suffered","Possesses information about qualifying criminal activity","Has been, is being, or is likely to be helpful to law enforcement","Law enforcement certification required: Form I-918 Supplement B","Certifying agency: police, prosecutor, judge, or other authority","10,000 annual cap — significant backlog/waitlist","4-year nonimmigrant status with work authorization","Path to LPR after 3 years continuous physical presence in U status","Derivative visas: spouse, children, parents (if principal is under 21), siblings (if principal is under 16)","Bona fide determination: deferred action and EAD while on waitlist","Waiver of inadmissibility grounds available (INA § 212(d)(14))"]', '[{"section":"101(a)(15)(U)(i)","description":"Four elements: victim, abuse, information, helpfulness"},{"section":"101(a)(15)(U)(iii)","description":"Qualifying criminal activity — enumerated crimes"},{"section":"214(p)(1)","description":"10,000 annual cap on U-visas"},{"section":"214(p)(2)","description":"Derivative family members eligible"},{"section":"214(p)(6)","description":"Waiver of inadmissibility available"},{"section":"245(m)","description":"Adjustment of status after 3 years in U status"}]', '["I-918_U_petition","I-918_Supp_B_law_enforcement_certification","personal_declaration","police_report","medical_records","I-192_inadmissibility_waiver","I-485_adjustment","derivative_family_petition"]', '["california-immigration-compliance-audit"]', 'USCIS Vermont Service Center', 0, 1, datetime('now'), datetime('now'));

-- T-Visa
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_109', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1101(a)(15)(T) (INA § 101(a)(15)(T) — T Nonimmigrant Status)', 'INA § 101(a)(15)(T) / T-Visa', 'T-Visa — Immigration Relief for Trafficking Victims', 'Provides immigration relief to victims of severe forms of trafficking in persons (sex trafficking or labor trafficking through force, fraud, or coercion). Physically present in US on account of trafficking. Must comply with reasonable law enforcement requests unless under 18 or unable due to trauma. 5,000 T-visas available annually (cap rarely reached). 4-year nonimmigrant status. Path to LPR after 3 years or upon completion of investigation/prosecution. No law enforcement certification required (unlike U-visa) but helpful.', '["Victim of severe form of trafficking in persons","Trafficking: sex trafficking by force/fraud/coercion, or labor trafficking through force/fraud/coercion/involuntary servitude","Physically present in US, American Samoa, CNMI, or port of entry on account of trafficking","Has complied with reasonable requests from law enforcement (or is under 18, or trauma exception)","Would suffer extreme hardship involving unusual and severe harm upon removal","No law enforcement certification required but LEA declaration helpful","5,000 annual cap (rarely reached)","4-year nonimmigrant status with work authorization","Path to LPR after 3 years continuous presence or completion of investigation","Derivative visas: spouse, children, parents, siblings (if principal under 21)","Broad inadmissibility waiver available","Services and benefits available: ORR certification letter for federal benefits"]', '[{"section":"101(a)(15)(T)(i)","description":"Four elements: victim, presence, compliance, extreme hardship"},{"section":"103(a) TVPA","description":"Severe forms of trafficking defined — sex and labor"},{"section":"214(o)(1)","description":"5,000 annual cap on T-visas"},{"section":"214(o)(2)","description":"Derivative family members eligible"},{"section":"214(o)(7)","description":"Waiver of inadmissibility — broad authority"},{"section":"245(l)","description":"Adjustment of status for T visa holders"}]', '["I-914_T_petition","I-914_Supp_B_LEA_declaration","personal_declaration","trafficking_evidence","ORR_certification_letter","I-192_inadmissibility_waiver","I-485_adjustment","derivative_family_petition"]', '["california-immigration-compliance-audit"]', 'USCIS Vermont Service Center', 0, 1, datetime('now'), datetime('now'));

-- VAWA Self-Petition
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_110', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1154(a)(1)(A)(iii)-(iv) / 8 USC § 1154(a)(1)(B)(ii)-(iii) (INA § 204(a) — VAWA Self-Petition)', 'INA § 204(a)(1)(A)(iii)-(iv) / VAWA', 'VAWA Self-Petition — Immigration Relief for Abused Spouses, Children, and Parents', 'Violence Against Women Act allows abused spouses, children, and parents of US citizens or LPRs to self-petition for immigrant status without the abuser''s knowledge or cooperation. Must demonstrate battery or extreme cruelty, good faith marriage (for spouse petitions), good moral character, and residence with the abuser. Self-petitioner controls the process — abuser never notified. Grants deferred action and work authorization upon prima facie determination. Path to LPR through adjustment of status or consular processing.', '["Abused spouse of USC or LPR may self-petition","Abused child of USC or LPR may self-petition","Abused parent of USC (adult child age 21+) may self-petition","Must demonstrate battery or extreme cruelty by USC/LPR spouse or parent","Good faith marriage required for spousal petitions","Good moral character of self-petitioner required","Must have resided with the abuser in the US","Abuser is NEVER notified — confidentiality protections (8 USC § 1367)","Prima facie determination triggers deferred action and EAD","Any credible evidence standard — no specific evidence type required","No income/affidavit of support requirement from abuser","Cancellation of removal available for VAWA self-petitioners (INA § 240A(b)(2))"]', '[{"section":"204(a)(1)(A)(iii)","description":"Self-petition by abused spouse of USC"},{"section":"204(a)(1)(A)(iv)","description":"Self-petition by abused child of USC"},{"section":"204(a)(1)(B)(ii)","description":"Self-petition by abused spouse of LPR"},{"section":"204(a)(1)(B)(iii)","description":"Self-petition by abused child of LPR"},{"section":"204(a)(1)(J)","description":"Any credible evidence standard"},{"section":"240A(b)(2)","description":"VAWA cancellation of removal — 3 years continuous presence"},{"section":"1367","description":"Confidentiality — abuser never notified, information not disclosed"}]', '["I-360_VAWA_self_petition","personal_declaration","evidence_of_abuse","police_reports","protective_orders","marriage_certificate","evidence_of_good_faith_marriage","evidence_of_residence","good_moral_character_evidence","EAD_application"]', '["california-immigration-compliance-audit"]', 'USCIS Vermont Service Center (VAWA Unit)', 0, 1, datetime('now'), datetime('now'));

-- Employer I-9 Obligations
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_111', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1324a (INA § 274A — Unlawful Employment of Aliens)', 'INA § 274A / 8 USC § 1324a', 'Employer I-9 Employment Verification Obligations', 'Requires all US employers to verify identity and employment authorization of every employee hired after November 6, 1986. Employer must complete Form I-9 within 3 business days of hire. Must examine original documents from List A (identity + work authorization) or List B (identity) + List C (work authorization). Cannot specify which documents to accept (anti-discrimination). E-Verify mandatory for federal contractors and some states. Penalties: $272-$2,701 per I-9 violation (paperwork), $676-$27,018 per unauthorized worker (knowingly hiring).', '["Must complete Form I-9 for every employee within 3 business days of hire","Section 1: Employee completes on or before first day of work","Section 2: Employer examines documents within 3 business days","List A documents: passport, permanent resident card, EAD — establish both identity and work authorization","List B + C documents: driver license (identity) + Social Security card (work authorization)","Cannot specify which documents — employee chooses (anti-discrimination provision)","Must accept documents that reasonably appear genuine","Must reverify expiring work authorization before expiration","Retain I-9 for 3 years after hire or 1 year after termination, whichever is later","E-Verify: mandatory for federal contractors (FAR E-Verify clause)","Penalties for knowingly hiring: $676-$5,404 (first), $5,404-$13,508 (second), $8,106-$27,018 (third+)","Penalties for I-9 paperwork violations: $272-$2,701 per form"]', '[{"section":"274A(a)(1)","description":"Prohibition on hiring unauthorized aliens"},{"section":"274A(a)(2)","description":"Prohibition on continued employment of unauthorized aliens"},{"section":"274A(b)","description":"Employment verification system — I-9 requirements"},{"section":"274A(e)","description":"Civil penalties for violations"},{"section":"274A(f)","description":"Criminal penalties for pattern or practice"},{"section":"274A(g)","description":"Anti-discrimination — unfair immigration-related employment practices"},{"section":"274B","description":"Unfair immigration-related employment practices — document abuse, citizenship discrimination"}]', '["I-9_form","List_A_documents","List_B_documents","List_C_documents","E-Verify_confirmation","I-9_audit_report","ICE_inspection_notice","civil_penalty_notice","anti_discrimination_policy"]', '["california-immigration-compliance-audit"]', 'ICE Homeland Security Investigations / DOJ Office of Special Counsel (IER)', 0, 1, datetime('now'), datetime('now'));

-- CA Values Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_112', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 7284-7284.12 (SB 54 — California Values Act)', 'GC §§ 7284-7284.12 / SB 54', 'California Values Act — Sanctuary State Protections', 'Limits state and local law enforcement cooperation with federal immigration enforcement. Prohibits use of state/local resources for immigration enforcement purposes. Law enforcement cannot inquire about immigration status, detain persons on ICE holds (with exceptions for serious/violent felonies), or provide personal information to immigration authorities. Does not prohibit compliance with federal law or sharing information about individuals convicted of specified crimes.', '["State/local law enforcement cannot use resources for immigration enforcement","Cannot inquire about immigration status in the course of duties","Cannot detain individuals on ICE detainer/hold requests (with exceptions)","Cannot provide personal information to immigration authorities","Cannot make arrests based solely on civil immigration warrants","Cannot participate in joint task forces for immigration enforcement","Exceptions: individuals convicted of specified serious/violent felonies (listed in GC § 7282.5)","Exceptions: individuals with pending charges for serious/violent felonies","Does not prohibit sending to or receiving from federal databases (CLETS, NCIC)","Does not restrict compliance with 8 USC § 1373 (limited information sharing)","Annual reporting by AG on detainer requests and responses","Applies to all state and local agencies, school police, campus police"]', '[{"section":"7284.2","description":"Legislative findings — trust between immigrant communities and state/local agencies"},{"section":"7284.4","description":"Definitions — California law enforcement agency, immigration authority, personal information"},{"section":"7284.6(a)","description":"Prohibitions on state/local immigration enforcement cooperation"},{"section":"7284.6(a)(1)","description":"Cannot use resources to investigate, interrogate, detain for immigration purposes"},{"section":"7284.6(a)(4)","description":"Cannot detain on ICE hold beyond release date"},{"section":"7284.6(b)","description":"Exceptions for serious/violent felony convictions"},{"section":"7284.8","description":"Notifications to individuals in custody about immigration agents"},{"section":"7284.10","description":"Annual AG reporting on detainer compliance"}]', '["agency_immigration_policy","detainer_response_log","AG_annual_report","training_materials","public_notification_posting","ICE_detainer_request","agency_compliance_audit"]', '["california-immigration-compliance-audit"]', 'California Attorney General / California Legislature', 0, 1, datetime('now'), datetime('now'));

-- CA Immigrant Tenant Protection Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_113', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1940.035 / Cal. Civ. Code § 1940.05 / Cal. Gov. Code § 1019.3 (AB 291 — Immigrant Tenant Protection Act)', 'CC § 1940.035 / AB 291', 'California Immigrant Tenant Protection Act — Protecting Tenants from Immigration Threats', 'Prohibits landlords from threatening to disclose immigration status to coerce tenants, from reporting or threatening to report tenants to immigration authorities in retaliation for exercising tenant rights, and from disclosing tenant immigration status to third parties or government agencies for purposes of harassment or retaliation. Landlord cannot inquire about immigration status. Violations are actionable as unlawful harassment and may subject landlord to actual damages, punitive damages, and attorney fees.', '["Landlord cannot disclose or threaten to disclose tenant immigration status","Cannot report or threaten to report tenant to immigration authorities in retaliation","Cannot inquire about immigration or citizenship status of tenants or applicants","Cannot restrict access to common areas based on immigration status","Threats related to immigration constitute harassment under CC § 1940.2","Violation: actual damages, statutory damages ($2,000-$5,000/violation for harassment), attorney fees","Immigration status irrelevant to tenant rights under California law","Applies regardless of tenant documentation status","AG and local prosecutors may bring enforcement actions","Tenant may void lease if landlord acted in retaliation using immigration threats"]', '[{"section":"1940.035(a)","description":"Prohibition on landlord disclosure of immigration status"},{"section":"1940.035(b)","description":"Prohibition on threatening immigration-related actions"},{"section":"1940.05","description":"Immigration status cannot affect tenant rights"},{"section":"1940.2","description":"Tenant harassment — immigration threats constitute harassment"},{"section":"GC 1019.3","description":"Prohibition on reporting immigration status in retaliation for exercising rights"}]', '["tenant_complaint","retaliation_claim","harassment_complaint","AG_complaint","lease_agreement","landlord_communication_records","eviction_defense"]', '["california-immigration-compliance-audit"]', 'California Attorney General / California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- DACA
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_114', 'REGULIS', 'FEDERAL_REGULATION', 'US', 'DHS Secretary Memorandum (June 15, 2012) — Deferred Action for Childhood Arrivals / ongoing litigation (Texas v. United States, S.D. Tex.)', 'DACA / DHS Memo 2012', 'Deferred Action for Childhood Arrivals — Status and Ongoing Litigation', 'Executive action providing deferred action (prosecutorial discretion not to remove) and employment authorization to individuals who entered the US as children. Established by DHS memorandum, not statute. Grants 2-year renewable deferred action and EAD. Subject to extensive ongoing litigation: DACA ruled unlawful by Southern District of Texas (2021), upheld in part by 5th Circuit (existing recipients may renew, no new applications). As of March 2026, renewal-only posture continues pending further litigation or legislative action.', '["Entered US before age 16","Continuously resided in US since June 15, 2007","Were under age 31 on June 15, 2012","Were physically present on June 15, 2012 and at time of application","No lawful immigration status on June 15, 2012","Currently enrolled in school, graduated/obtained GED, or honorably discharged from military","No felony conviction, significant misdemeanor, or three or more misdemeanors","Do not pose threat to national security or public safety","2-year deferred action with employment authorization (EAD)","Renewal applications continue to be processed (as of March 2026)","New initial applications not being accepted per court order","Does not provide lawful status, path to LPR, or any immigration benefit beyond deferred action","Subject to termination — no vested right to continuation"]', '[{"section":"DHS Memo 2012","description":"Original DACA memorandum — prosecutorial discretion framework"},{"section":"Texas v. United States (S.D. Tex.)","description":"DACA ruled unlawful — no new applications, renewals continue"},{"section":"DHS v. Regents (2020)","description":"Supreme Court: rescission was arbitrary and capricious (procedural, not substantive)"},{"section":"8 CFR 236.21-236.25","description":"DHS regulatory attempt to codify DACA (enjoined)"}]', '["I-821D_DACA_application","EAD_application","biometric_appointment","renewal_application","evidence_of_continuous_residence","education_records","background_check_results"]', '["california-immigration-compliance-audit"]', 'USCIS', 0, 1, datetime('now'), datetime('now'));

-- Temporary Protected Status
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_115', 'REGULIS', 'FEDERAL_STATUTE', 'US', '8 USC § 1254a (INA § 244 — Temporary Protected Status)', 'INA § 244 / 8 USC § 1254a', 'Temporary Protected Status — Protection for Nationals of Designated Countries', 'Secretary of DHS may designate countries for TPS based on ongoing armed conflict, environmental disaster, or other extraordinary and temporary conditions. Nationals of designated countries who are present in the US may register for TPS, which provides protection from removal and work authorization for the designation period (6-18 months, renewable). Does not lead directly to LPR status but TPS holders may be eligible for other immigration benefits. Current designated countries include: El Salvador, Haiti, Honduras, Nepal, Nicaragua, Somalia, South Sudan, Sudan, Syria, Ukraine, Venezuela, and others.', '["DHS Secretary designates countries based on armed conflict, environmental disaster, or extraordinary conditions","Must be national of designated country (or stateless person who last habitually resided there)","Must have been continuously physically present in US since designation date","Must have been continuously residing in US since date specified in Federal Register","Must register during initial registration period or re-registration period","Must not have been convicted of any felony or two or more misdemeanors","Must not be found inadmissible as an immigrant on certain grounds","Designation period: 6-18 months, may be extended or terminated","Provides protection from removal and employment authorization","Does not provide path to LPR directly (but may apply for other benefits)","Late initial registration possible if good cause shown","Travel authorization available via advance parole (Form I-131)"]', '[{"section":"244(b)(1)","description":"Designation criteria — armed conflict, environmental disaster, extraordinary conditions"},{"section":"244(b)(2)","description":"Duration of designation — 6-18 months, renewable"},{"section":"244(c)(1)","description":"Eligibility requirements — nationality, presence, residence"},{"section":"244(c)(2)","description":"Registration requirement and period"},{"section":"244(c)(2)(B)","description":"Criminal bars — felony, two misdemeanors"},{"section":"244(d)","description":"Documentation and employment authorization"},{"section":"244(f)(4)","description":"No basis for adjustment of status to LPR (with exceptions via other provisions)"}]', '["I-821_TPS_application","EAD_application","I-131_advance_parole","country_conditions_evidence","Federal_Register_designation","re-registration_notice","nationality_documentation"]', '["california-immigration-compliance-audit"]', 'USCIS', 0, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — Insurance Law
-- ═══════════════════════════════════════════════════════════════════════════

-- CA Unfair Insurance Practices Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_116', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Ins. Code §§ 790-790.15 (Unfair Insurance Practices Act)', 'Ins Code §§ 790-790.15', 'California Unfair Insurance Practices Act — Prohibited Insurer Conduct', 'Prohibits unfair methods of competition and unfair or deceptive acts or practices in the business of insurance. Defines unfair claims settlement practices, misrepresentation, false advertising, defamation, boycott, intimidation, and other prohibited conduct. Commissioner of Insurance may investigate, hold hearings, issue cease and desist orders, and impose penalties. No direct private right of action under this act (Moradi-Shalal v. Fireman''s Fund, 1988), but violations may support bad faith tort claims.', '["Misrepresentation and false advertising of insurance policies prohibited","Defamation of competitors prohibited","Boycott, coercion, and intimidation prohibited","Unfair claims settlement practices prohibited (detailed in § 790.03(h))","False statements and entries prohibited","Unfair discrimination prohibited","Rebates prohibited (with limited exceptions)","Commissioner may examine and investigate insurers","Commissioner may issue cease and desist orders","Penalties: up to $5,000 per violation, up to $10,000 if willful","License suspension or revocation for violations","No direct private right of action (Moradi-Shalal v. Fireman''s Fund, 1988)","Violations may be evidence supporting common law bad faith claims"]', '[{"section":"790.02","description":"Unfair methods of competition and deceptive acts prohibited"},{"section":"790.03","description":"Enumeration of unfair practices — misrepresentation, defamation, boycott, unfair claims settlement"},{"section":"790.03(h)","description":"Unfair claims settlement practices — 16 enumerated acts"},{"section":"790.035","description":"Knowingly committing or performing with such frequency to indicate general business practice"},{"section":"790.04","description":"Commissioner authority to examine and investigate"},{"section":"790.05","description":"Hearing procedure for alleged violations"},{"section":"790.06","description":"Cease and desist orders"},{"section":"790.09","description":"Penalties — $5,000 per violation, $10,000 if willful"}]', '["DOI_complaint","market_conduct_examination","cease_and_desist_order","administrative_hearing","penalty_assessment","insurer_compliance_audit","claims_handling_review"]', '["california-insurance-compliance-audit"]', 'California Department of Insurance (CDI)', 0, 1, datetime('now'), datetime('now'));

-- CA Fair Claims Settlement Practices
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_117', 'REGULIS', 'STATE_REGULATION', 'CA', 'Cal. Code Regs. Title 10, §§ 2695.1-2695.17 (Fair Claims Settlement Practices Regulations)', 'CCR Title 10 §§ 2695.1-2695.17', 'California Fair Claims Settlement Practices Regulations', 'Detailed regulations implementing Insurance Code § 790.03(h) unfair claims settlement practices. Establishes specific timeframes: acknowledge claim within 15 days, accept/deny within 40 days, pay within 30 days of settlement. Requires written basis for claim denial. Prohibits requiring claimant to make unnecessary trips or contact. Applies to all lines of insurance. Violations constitute unfair claims settlement practices and may support bad faith tort claims.', '["Acknowledge receipt of claim within 15 calendar days","Accept or deny claim within 40 calendar days of receipt of proof of claim","Pay accepted claims within 30 calendar days of settlement agreement","Provide written explanation for claim denial with specific policy provisions","Cannot require forms that duplicate information already provided","Must conduct reasonable investigation before denying claim","Cannot compel claimants to initiate litigation to recover amounts due","Cannot make settlement offers substantially below reasonable value","Must advise claimant of right to present matter to Department of Insurance","Must maintain claims files and document basis for all decisions","Cannot misrepresent pertinent facts or policy provisions","Insurer must provide status updates every 30 days on pending claims"]', '[{"section":"2695.4","description":"File and record documentation requirements"},{"section":"2695.5","description":"Communication and cooperation — 15-day acknowledgment"},{"section":"2695.7(a)","description":"Standards for prompt investigation"},{"section":"2695.7(b)","description":"40-day acceptance/denial deadline"},{"section":"2695.7(c)","description":"Written basis for denial required"},{"section":"2695.7(d)","description":"30-day payment after settlement"},{"section":"2695.7(g)","description":"Offer must be reasonable — cannot lowball"},{"section":"2695.9","description":"Additional standards for first-party residential/commercial property claims"},{"section":"2695.10","description":"Additional standards for automobile insurance claims"},{"section":"2695.17","description":"CDI complaint rights notification"}]', '["claim_acknowledgment","claim_denial_letter","settlement_offer","proof_of_claim","claims_investigation_report","CDI_complaint","payment_records","status_update_correspondence"]', '["california-insurance-compliance-audit"]', 'California Department of Insurance (CDI)', 0, 1, datetime('now'), datetime('now'));

-- Insurance Bad Faith
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_118', 'REGULIS', 'CASE_LAW', 'CA', 'Egan v. Mutual of Omaha Insurance Co. (1979) 24 Cal.3d 809; Gruenberg v. Aetna Insurance Co. (1973) 9 Cal.3d 566', 'Egan v. Mutual of Omaha (1979)', 'Insurance Bad Faith — Breach of Implied Covenant of Good Faith and Fair Dealing', 'Every insurance contract contains an implied covenant of good faith and fair dealing. Breach occurs when insurer unreasonably withholds benefits due under the policy. Gruenberg (1973) established tort cause of action for bad faith denial of insurance benefits. Egan (1979) confirmed punitive damages available for bad faith. Insurer must thoroughly investigate, objectively evaluate, and fairly pay legitimate claims. Genuine dispute doctrine (Chateau Chamberay, 2001): no bad faith if insurer''s position was reasonable and based on genuine dispute as to coverage or liability.', '["Implied covenant of good faith and fair dealing in every insurance contract","Tort cause of action — not just breach of contract (Gruenberg v. Aetna)","Must genuinely investigate claims before denial","Must not unreasonably delay or deny benefits due under policy","Must not misrepresent policy terms to avoid coverage","Must not lowball claims to force acceptance of inadequate settlement","Punitive damages available for oppression, fraud, or malice (CC § 3294)","Emotional distress damages recoverable in first-party bad faith","Genuine dispute doctrine: no bad faith if reasonable dispute exists (Chateau Chamberay)","Must give at least as much consideration to insured''s interest as to its own","Third-party bad faith: failure to settle within policy limits exposes insurer to excess judgment","Statute of limitations: 2 years for tort bad faith (CCP § 339)"]', '[{"section":"Gruenberg v. Aetna (1973)","description":"Established tort cause of action for bad faith denial of insurance benefits"},{"section":"Egan v. Mutual of Omaha (1979)","description":"Punitive damages available — insurer must consider insured''s interests"},{"section":"Neal v. Farmers Ins. (1978)","description":"Third-party bad faith — duty to accept reasonable settlement within limits"},{"section":"Chateau Chamberay v. AAA (2001)","description":"Genuine dispute doctrine — reasonable basis negates bad faith"},{"section":"CC § 3294","description":"Punitive damages standard — oppression, fraud, or malice"},{"section":"Brandt v. Superior Court (1985)","description":"Attorney fees recoverable as consequential damages in bad faith"}]', '["bad_faith_complaint","claims_file","denial_letter","settlement_demand","Brandt_fee_claim","punitive_damages_evidence","insurer_internal_communications","expert_declaration","claims_handling_guidelines"]', '["california-insurance-compliance-audit"]', 'California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- CA Insurance Code § 790.03 — Unfair Claims Practices
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_119', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Ins. Code § 790.03(h) — Unfair Claims Settlement Practices (16 Enumerated Acts)', 'Ins Code § 790.03(h)', 'California Insurance Code § 790.03(h) — Sixteen Enumerated Unfair Claims Practices', 'Enumerates 16 specific unfair claims settlement practices that constitute violations of the Unfair Insurance Practices Act when committed knowingly or with such frequency as to indicate a general business practice. Forms the statutory basis for CDI enforcement and evidentiary foundation for common law bad faith claims. Each enumerated act addresses a specific form of insurer misconduct in claims handling.', '["(1) Misrepresenting pertinent facts or policy provisions relating to coverages at issue","(2) Failing to acknowledge and act reasonably promptly on communications","(3) Failing to adopt reasonable standards for prompt investigation and processing","(4) Failing to affirm or deny coverage within reasonable time after proof of claim","(5) Not attempting in good faith to effectuate prompt, fair, equitable settlements when liability is clear","(6) Compelling insureds to institute litigation by offering substantially less than reasonable","(7) Attempting to settle for less than reasonable expectation under advertising","(8) Attempting to settle on basis of application altered without consent","(9) Failing to promptly provide reasonable explanation of denial basis","(10) Making claims payments without including statement of coverage","(11) Making known appeals policy of compelling arbitration by offering less than owed","(12) Delaying investigation by requiring duplicative documentation","(13) Failing to settle promptly where liability clear under one portion to influence other portion","(14) Failing to provide notice of statute of limitations or other time limitation","(15) Making false or misleading statements to claimant''s attorney regarding applicable statute of limitations","(16) Not complying with the provisions of Section 790.034 (post-disaster claims)"]', '[{"section":"790.03(h)(1)","description":"Misrepresenting facts or policy provisions"},{"section":"790.03(h)(2)","description":"Failing to acknowledge communications promptly"},{"section":"790.03(h)(3)","description":"Failing to adopt reasonable investigation standards"},{"section":"790.03(h)(4)","description":"Failing to affirm or deny coverage within reasonable time"},{"section":"790.03(h)(5)","description":"Not attempting good faith fair settlement when liability clear"},{"section":"790.03(h)(6)","description":"Compelling litigation by offering substantially less than owed"},{"section":"790.03(h)(7)","description":"Settling for less than advertising would reasonably suggest"},{"section":"790.03(h)(9)","description":"Failing to provide reasonable explanation of denial basis"},{"section":"790.03(h)(12)","description":"Delaying investigation by requiring duplicative documentation"},{"section":"790.03(h)(13)","description":"Failing to settle clear portion to influence disputed portion"},{"section":"790.03(h)(14)-(15)","description":"Statute of limitations notice and misrepresentation"},{"section":"790.03(h)(16)","description":"Post-disaster claims compliance (§ 790.034)"}]', '["claims_denial_analysis","CDI_market_conduct_report","claims_file_audit","unfair_practices_complaint","settlement_offer_evaluation","insurer_training_records","claims_handling_manual"]', '["california-insurance-compliance-audit"]', 'California Department of Insurance (CDI)', 0, 1, datetime('now'), datetime('now'));

-- ERISA Preemption
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_120', 'REGULIS', 'FEDERAL_STATUTE', 'US', '29 USC § 1144 (ERISA § 514 — Preemption)', 'ERISA § 514 / 29 USC § 1144', 'ERISA Preemption — Federal Supremacy over Employee Benefit Plans', 'ERISA broadly preempts state laws that "relate to" employee benefit plans, creating exclusive federal regulatory framework. Three-part preemption analysis: (1) preemption clause — supersedes all state laws relating to employee benefit plans; (2) savings clause — saves state laws that regulate insurance; (3) deemer clause — prevents states from deeming employee benefit plans to be insurance companies. Practical effect: self-funded employer health plans are effectively exempt from state insurance regulation. Completely preempts state law claims for benefits, creating exclusive federal jurisdiction.', '["Preemption clause: ERISA supersedes any state law that relates to employee benefit plan","Savings clause: state laws regulating insurance are saved from preemption","Deemer clause: benefit plans cannot be deemed insurance companies (self-funded plans exempt from state regulation)","Complete preemption: claims for benefits under § 502(a) are exclusively federal","Self-funded employer plans: not subject to state insurance mandates, taxes, or regulation","Fully insured plans: subject to state insurance regulation via savings clause","Preemption applies to both pension and welfare benefit plans","Church plans and governmental plans generally exempt from ERISA","Remedies limited under ERISA: no punitive damages, limited extracontractual damages","State bad faith and unfair practices claims preempted for ERISA plans"]', '[{"section":"514(a)","description":"Preemption clause — supersedes state laws relating to employee benefit plans"},{"section":"514(b)(2)(A)","description":"Savings clause — saves state insurance regulation"},{"section":"514(b)(2)(B)","description":"Deemer clause — plans cannot be deemed insurers"},{"section":"514(d)","description":"Does not alter federal/state criminal law"},{"section":"Pilot Life v. Dedeaux (1987)","description":"State bad faith claims completely preempted"},{"section":"FMC Corp. v. Holliday (1990)","description":"Self-funded plans exempt from state insurance laws via deemer clause"},{"section":"Kentucky Ass''n v. Miller (2003)","description":"Two-part savings clause test: directed at insurance industry, substantial effect on risk pooling"}]', '["ERISA_preemption_analysis","plan_document_review","self-funded_vs_insured_determination","removal_to_federal_court","preemption_motion","plan_classification","state_mandate_compliance"]', '["california-insurance-compliance-audit"]', 'DOL Employee Benefits Security Administration (EBSA) / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- ERISA Fiduciary Duties
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_121', 'REGULIS', 'FEDERAL_STATUTE', 'US', '29 USC § 1104 (ERISA § 404 — Fiduciary Duties)', 'ERISA § 404 / 29 USC § 1104', 'ERISA Fiduciary Duties — Prudence, Loyalty, and Diversification', 'Establishes fiduciary duties for persons who exercise discretionary authority or control over ERISA plan management, assets, or administration. Four core duties: (1) exclusive purpose/loyalty — act solely in interest of participants and beneficiaries; (2) prudent expert standard — care, skill, prudence, and diligence of a prudent person in like capacity; (3) diversification — diversify investments to minimize risk of large losses; (4) plan document compliance — act in accordance with plan documents consistent with ERISA. Personal liability for breach of fiduciary duty.', '["Exclusive purpose rule: act solely in the interest of participants and beneficiaries","Prudent expert standard: care, skill, prudence, and diligence under the circumstances","Diversification: diversify plan investments to minimize risk of large losses","Plan document rule: adhere to plan documents insofar as consistent with ERISA","Prohibited transactions: cannot engage in self-dealing or conflicts of interest (§ 406)","Co-fiduciary liability: fiduciary liable for breach by co-fiduciary if participates, enables, or fails to remedy","Personal liability: fiduciary personally liable to make plan whole for losses from breach","Cannot exculpate — agreements to relieve fiduciary of liability are void","Functional test: fiduciary status determined by function, not title","Investment policy statement should be maintained and followed"]', '[{"section":"404(a)(1)(A)","description":"Exclusive purpose — solely in interest of participants and beneficiaries"},{"section":"404(a)(1)(B)","description":"Prudent expert standard — care, skill, prudence, diligence"},{"section":"404(a)(1)(C)","description":"Diversification — minimize risk of large losses"},{"section":"404(a)(1)(D)","description":"Plan document compliance"},{"section":"405(a)","description":"Co-fiduciary liability"},{"section":"406","description":"Prohibited transactions — self-dealing, conflicts of interest"},{"section":"409(a)","description":"Personal liability for breach — make plan whole"},{"section":"410(a)","description":"Exculpatory provisions void"}]', '["fiduciary_determination","investment_policy_statement","plan_document","fee_disclosure","prohibited_transaction_analysis","fiduciary_liability_insurance","DOL_investigation","breach_of_fiduciary_complaint"]', '["california-insurance-compliance-audit"]', 'DOL Employee Benefits Security Administration (EBSA) / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- ERISA Claims Procedure
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_122', 'REGULIS', 'FEDERAL_STATUTE', 'US', '29 USC § 1133 (ERISA § 503) / 29 CFR § 2560.503-1 (Claims Procedure Regulation)', 'ERISA § 503 / 29 CFR § 2560.503-1', 'ERISA Claims Procedure — Administrative Exhaustion and Appeal Rights', 'Requires every ERISA plan to establish reasonable claims procedures providing adequate written notice of claim denial with specific reasons, and opportunity for full and fair review of denied claims. DOL regulations (29 CFR § 2560.503-1) specify detailed timing requirements: 30 days for non-urgent pre-service claims, 72 hours for urgent care, 45 days for disability claims (extendable). Must exhaust administrative remedies before filing federal lawsuit. Failure to follow procedures may result in deemed exhaustion.', '["Written claim denial must include specific reason(s) for denial","Must reference specific plan provisions on which denial is based","Must describe additional material needed and explain why","Must describe plan''s review procedures and time limits","Must inform claimant of right to bring civil action under § 502(a)","Timing — non-urgent pre-service: 30 days (15-day extension)","Timing — urgent care: 72 hours","Timing — post-service: 30 days (15-day extension)","Timing — disability claims: 45 days (two 30-day extensions)","Appeal: 180 days to file appeal of denied claim","Appeal decision: 60 days (non-disability), 45 days (disability, with 45-day extension)","Full and fair review: must consider all evidence, not limited to initial determination","Must provide claimant access to relevant documents free of charge","Administrative exhaustion required before federal court action","Deemed exhaustion: if plan fails to follow procedures, claimant deemed to have exhausted"]', '[{"section":"503(1)","description":"Adequate written notice of denial with specific reasons"},{"section":"503(2)","description":"Reasonable opportunity for full and fair review"},{"section":"2560.503-1(f)","description":"Timing of initial claim determination"},{"section":"2560.503-1(g)","description":"Content of denial notice — specific information required"},{"section":"2560.503-1(h)","description":"Appeal procedures — full and fair review requirements"},{"section":"2560.503-1(i)","description":"Timing of appeal determination"},{"section":"2560.503-1(l)","description":"Deemed exhaustion for procedural failures"},{"section":"502(a)(1)(B)","description":"Civil action to recover benefits, enforce rights, clarify future benefits"}]', '["claim_submission","claim_denial_notice","appeal_letter","appeal_determination","administrative_record","plan_document","SPD","civil_complaint","deemed_exhaustion_notice"]', '["california-insurance-compliance-audit"]', 'DOL Employee Benefits Security Administration (EBSA) / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- CA Independent Medical Review
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_123', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Ins. Code §§ 10169-10169.5 / Cal. Health & Safety Code §§ 1374.30-1374.36 (Independent Medical Review)', 'Ins Code §§ 10169-10169.5', 'California Independent Medical Review — External Review of Health Insurance Denials', 'Provides insured persons the right to an independent medical review (IMR) when a health insurer denies, modifies, or delays a service based on medical necessity, experimental/investigational determination, or urgency. DMHC administers IMR for HMO/managed care; CDI administers for indemnity/PPO plans. IMR decision is binding on the insurer. No cost to the insured. Available after exhausting internal grievance/appeal (or immediately for urgent cases). IMR reviewers are independent physicians with no financial interest in the outcome.', '["Available when insurer denies based on medical necessity or experimental/investigational","Must exhaust internal grievance process first (exception: urgent/imminent threat)","No cost to the insured for IMR process","DMHC administers IMR for HMO plans (H&S Code §§ 1374.30-1374.36)","CDI administers IMR for PPO/indemnity plans (Ins Code §§ 10169-10169.5)","IMR decision is binding on the health plan/insurer","Independent physicians review — no financial connection to plan","Expedited IMR available for urgent cases (3 business days)","Standard IMR determination within 30 days","Insurer must implement IMR decision within 5 business days","IMR reviewer has access to complete medical record","Reviewers must be board-certified in relevant specialty"]', '[{"section":"10169(a)","description":"Right to independent medical review for CDI-regulated plans"},{"section":"10169.1","description":"Application process and eligibility criteria"},{"section":"10169.2","description":"IMR organization requirements and reviewer qualifications"},{"section":"10169.3","description":"Review standards — medically necessary, appropriate, effective"},{"section":"10169.4","description":"IMR determination — binding on insurer, 30-day timeline"},{"section":"10169.5","description":"Expedited review for urgent cases — 3 business days"},{"section":"1374.30","description":"DMHC IMR for managed care — equivalent provisions"},{"section":"1374.33","description":"DMHC IMR determination binding on plan"}]', '["IMR_application","grievance_file","medical_records","denial_letter","treating_physician_statement","IMR_determination","expedited_review_request","plan_compliance_response"]', '["california-insurance-compliance-audit"]', 'California Department of Managed Health Care (DMHC) / California Department of Insurance (CDI)', 0, 1, datetime('now'), datetime('now'));

-- CA Health Insurance Parity — Mental Health
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_124', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Ins. Code § 10144.5 / Cal. Health & Safety Code § 1374.72 / Cal. Ins. Code § 10123.15 (Mental Health Parity)', 'Ins Code § 10144.5 / H&S § 1374.72', 'California Mental Health Parity — Equal Coverage for Mental Health and Substance Use', 'California requires health insurers and managed care plans to provide coverage for mental health and substance use disorder services on parity with medical/surgical benefits. No separate deductibles, copays, or visit limits that are more restrictive than those for medical/surgical conditions. Covers all DSM-5 diagnoses. Applies to both individual and group plans. California law is more protective than federal MHPAEA (Mental Health Parity and Addiction Equity Act) in several respects, including mandatory coverage (not just parity if offered).', '["Mental health benefits must be provided on parity with medical/surgical benefits","No separate or more restrictive deductibles for mental health","No separate or more restrictive copays or coinsurance for mental health","No day or visit limits more restrictive than for medical/surgical","Coverage required for all DSM-5 diagnoses","Substance use disorder treatment covered at parity","Quantitative treatment limitations must be at parity","Non-quantitative treatment limitations (NQTLs) must be comparable — prior authorization, step therapy, network adequacy","Must cover outpatient, inpatient, partial hospitalization, and residential treatment","Applied to both individual and group health plans","Network adequacy: must maintain adequate MH/SUD provider network","SB 855 (2020): codified parity requirements and established clinical criteria standards"]', '[{"section":"10144.5","description":"Mental health parity for CDI-regulated plans"},{"section":"1374.72","description":"Mental health parity for DMHC-regulated plans"},{"section":"10123.15","description":"Substance use disorder coverage requirements"},{"section":"SB 855 (Ins Code § 10144.52)","description":"Generally accepted standards of mental health/SUD care — clinical criteria"},{"section":"10144.52(a)","description":"Must use clinical criteria consistent with generally accepted standards"},{"section":"1374.721","description":"DMHC parity compliance — NQTLs"}]', '["parity_compliance_analysis","benefit_comparison_chart","NQTL_analysis","network_adequacy_report","grievance_filing","DMHC_complaint","CDI_complaint","SB_855_compliance_audit","prior_authorization_review"]', '["california-insurance-compliance-audit"]', 'California Department of Managed Health Care (DMHC) / California Department of Insurance (CDI)', 0, 1, datetime('now'), datetime('now'));

-- Unruh Civil Rights Act — Insurance
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_125', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 51 (Unruh Civil Rights Act — Insurance Application)', 'CC § 51 / Unruh Act', 'Unruh Civil Rights Act — Anti-Discrimination in Insurance as Business Establishment', 'The Unruh Civil Rights Act guarantees all persons full and equal accommodations in all business establishments, including insurance companies. Prohibits discrimination based on sex, race, color, religion, ancestry, national origin, disability, medical condition, genetic information, marital status, sexual orientation, citizenship, primary language, and immigration status. Insurance companies cannot use protected characteristics as underwriting criteria unless actuarially justified. Statutory damages of $4,000 minimum per violation plus actual damages and attorney fees.', '["Full and equal accommodations in all business establishments including insurers","Cannot discriminate in underwriting based on protected characteristics","Protected categories include: sex, race, color, religion, ancestry, national origin, disability, medical condition, genetic information, marital status, sexual orientation, citizenship, primary language, immigration status","Actuarial justification defense: insurer may use otherwise prohibited factor if based on sound actuarial principles","Statutory minimum damages: $4,000 per violation","Actual damages in addition to statutory minimum","Attorney fees and costs to prevailing plaintiff","Treble damages available in some circumstances","Any ADA violation is also an Unruh violation (Munson v. Del Taco, 2009)","Immigration status cannot be used to deny insurance coverage","Gender-based pricing restrictions (Proposition 103 interaction)"]', '[{"section":"51(a)","description":"Equal rights — full and equal accommodations, advantages, facilities, privileges, services"},{"section":"51(b)","description":"Enumerated protected categories"},{"section":"51(e)","description":"Immigration or citizenship status — cannot discriminate"},{"section":"51(f)","description":"Any violation of ADA is violation of Unruh"},{"section":"52(a)","description":"Damages — $4,000 statutory minimum plus actual damages"},{"section":"52(b)","description":"Injunctive relief available"},{"section":"52(c)","description":"Attorney fees to prevailing plaintiff"}]', '["Unruh_complaint","insurance_discrimination_complaint","underwriting_review","actuarial_justification","civil_complaint","CRD_complaint","damages_calculation","rate_filing_review"]', '["california-insurance-compliance-audit"]', 'California Civil Rights Department (CRD) / California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- CA Proposition 103
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_126', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Ins. Code §§ 1861.01-1861.16 (Proposition 103 — Insurance Rate Regulation)', 'Ins Code §§ 1861.01-1861.16 / Prop 103', 'California Proposition 103 — Insurance Rate Regulation and Prior Approval', 'Voter-approved initiative (1988) establishing prior approval system for property, casualty, and auto insurance rates. Rates must not be excessive, inadequate, or unfairly discriminatory. Commissioner must approve rate changes before implementation. Auto insurance mandatory rating factors in order of importance: (1) driving safety record, (2) miles driven per year, (3) years of driving experience. Prohibits use of ZIP code/territory as primary rating factor. Provides for public intervenor process — consumers may challenge rate filings and recover attorney fees.', '["Prior approval required for all rate changes — rates cannot be used until approved","Rates must not be excessive, inadequate, or unfairly discriminatory","Auto insurance mandatory rating factors (in order): driving safety record, annual mileage, years of experience","Prohibited auto rating factors: ZIP code/territory as primary factor, credit score (SB 1273)","Good driver discount: 20% mandatory discount for safe driving record","Public intervenor process: consumers and organizations may challenge rate filings","Intervenor attorney fees: Commissioner may award fees to intervenors who make substantial contribution","Commissioner elected by voters (not appointed by Governor)","Rollback and freeze provisions (initial implementation)","Annual rate filings required for all regulated lines","Insurer must justify rate increases with actuarial data","Rate hearing process for contested filings"]', '[{"section":"1861.01(a)","description":"Rates cannot be excessive, inadequate, or unfairly discriminatory"},{"section":"1861.01(b)","description":"Prior approval required — no rate effective without approval"},{"section":"1861.02(a)","description":"Auto insurance mandatory rating factors — safety, mileage, experience"},{"section":"1861.02(b)","description":"Optional rating factors must be approved and substantially related to risk"},{"section":"1861.02(c)","description":"Good driver discount — 20% mandatory"},{"section":"1861.05","description":"Rate filing requirements and public access"},{"section":"1861.06","description":"Commissioner approval or disapproval of rate filings"},{"section":"1861.10","description":"Public intervenor process — consumer participation"},{"section":"1861.10(c)","description":"Intervenor fees — substantial contribution standard"},{"section":"1861.16","description":"Commissioner election by voters"}]', '["rate_filing","actuarial_justification","public_intervenor_petition","rate_hearing_testimony","consumer_rate_challenge","good_driver_discount_verification","CDI_rate_decision","rating_factor_analysis"]', '["california-insurance-compliance-audit"]', 'California Department of Insurance (CDI) / Elected Insurance Commissioner', 0, 1, datetime('now'), datetime('now'));

-- CA Auto Insurance — Financial Responsibility
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_127', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Veh. Code §§ 16020-16033 (Financial Responsibility)', 'Veh Code §§ 16020-16033', 'California Auto Insurance — Financial Responsibility Requirements', 'All California vehicle owners and operators must maintain financial responsibility (insurance) at all times. Minimum liability limits: $15,000 per person / $30,000 per accident bodily injury, $5,000 property damage (15/30/5). Must carry evidence of insurance in vehicle. Failure to maintain insurance: DMV may suspend registration, fine of $100-$200 (first offense) up to $500 (subsequent), vehicle impoundment. Low Cost Automobile Insurance Program (CLCA) available for income-eligible drivers. Electronic proof of insurance accepted.', '["Must maintain liability insurance at all times vehicle is operated or registered","Minimum limits: $15,000/$30,000 bodily injury, $5,000 property damage","Must carry evidence of insurance in vehicle — electronic proof accepted","Must provide proof of insurance at traffic stop, accident, or registration","Alternatives to insurance: surety bond ($35,000), cash deposit ($35,000), self-insurance certificate","Failure to maintain: registration suspension by DMV","Penalties: $100-$200 fine (first offense), up to $500 (subsequent), vehicle impoundment up to 30 days","Uninsured motorist involved in accident: 1-year license suspension, 3-year SR-22 filing","SR-22: certificate of financial responsibility filed with DMV for 3 years","CLCA (California Low Cost Auto Insurance): available for income-eligible drivers","DMV electronic insurance verification system","Insurers must report policy cancellations to DMV electronically"]', '[{"section":"16020(a)","description":"Financial responsibility required for all vehicle owners/operators"},{"section":"16020(b)","description":"Evidence of financial responsibility must be carried in vehicle"},{"section":"16021","description":"Electronic proof of insurance accepted"},{"section":"16025","description":"Penalties for failure to provide proof — $100-$200 fine"},{"section":"16028","description":"Proof required at traffic stop, accident, registration"},{"section":"16029","description":"DMV registration suspension for uninsured vehicles"},{"section":"16030","description":"Self-insurance certificate alternative"},{"section":"16054","description":"SR-22 filing requirement after uninsured accident"},{"section":"16056","description":"3-year SR-22 maintenance requirement"},{"section":"11629.7","description":"California Low Cost Auto Insurance Program (CLCA)"}]', '["insurance_card","SR-22_filing","DMV_suspension_notice","registration_renewal","CLCA_application","surety_bond","self_insurance_certificate","accident_report","proof_of_insurance"]', '["california-insurance-compliance-audit"]', 'California DMV / California Department of Insurance (CDI)', 0, 1, datetime('now'), datetime('now'));
